import{_ as i,o as l,c as o,ai as r}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"对话记录清理","description":"","frontmatter":{"read_when":["你正在调试与对话记录结构相关的提供商请求拒绝问题","你正在修改对话记录清理或工具调用修复逻辑","你正在调查跨提供商的工具调用 id 不匹配问题"],"summary":"参考：提供商特定的对话记录清理与修复规则","title":"对话记录清理","x-i18n":{"generated_at":"2026-02-01T21:38:16Z","model":"claude-opus-4-5","provider":"pi","source_hash":"6ce62fad0b07c4d8575c9cdb1c8c2663695ef2d4221cf4a0964fce03461523af","source_path":"reference/transcript-hygiene.md","workflow":15}},"headers":[],"relativePath":"zh-CN/reference/transcript-hygiene.md","filePath":"zh-CN/reference/transcript-hygiene.md","lastUpdated":1771906665000}'),n={name:"zh-CN/reference/transcript-hygiene.md"};function s(t,e,a,c,d,p){return l(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="对话记录清理-提供商修正" tabindex="-1"><a class="header-anchor" href="#对话记录清理-提供商修正">#</a> 对话记录清理（提供商修正）</h1><p>本文档描述了在运行前（构建模型上下文时）应用于对话记录的<strong>提供商特定修正</strong>。这些是<strong>内存中</strong>的调整，用于满足提供商的严格要求。它们<strong>不会</strong>重写磁盘上存储的 JSONL 对话记录。</p><p>涵盖范围包括：</p><ul><li>工具调用 id 清理</li><li>工具结果配对修复</li><li>轮次验证 / 排序</li><li>思考签名清理</li><li>图片负载清理</li></ul><p>如需了解对话记录存储细节，请参阅：</p><ul><li><a href="/docs/reference/session-management-compaction">/reference/session-management-compaction</a></li></ul><hr><h2 id="运行位置" tabindex="-1"><a class="header-anchor" href="#运行位置">#</a> 运行位置</h2><p>所有对话记录清理逻辑集中在嵌入式运行器中：</p><ul><li>策略选择：<code>src/agents/transcript-policy.ts</code></li><li>清理/修复应用：<code>src/agents/pi-embedded-runner/google.ts</code> 中的 <code>sanitizeSessionHistory</code></li></ul><p>策略根据 <code>provider</code>、<code>modelApi</code> 和 <code>modelId</code> 来决定应用哪些规则。</p><hr><h2 id="全局规则-图片清理" tabindex="-1"><a class="header-anchor" href="#全局规则-图片清理">#</a> 全局规则：图片清理</h2><p>图片负载始终会被清理，以防止因大小限制导致提供商端拒绝（对超大 base64 图片进行缩放/重新压缩）。</p><p>实现：</p><ul><li><code>src/agents/pi-embedded-helpers/images.ts</code> 中的 <code>sanitizeSessionMessagesImages</code></li><li><code>src/agents/tool-images.ts</code> 中的 <code>sanitizeContentBlocksImages</code></li></ul><hr><h2 id="提供商矩阵-当前行为" tabindex="-1"><a class="header-anchor" href="#提供商矩阵-当前行为">#</a> 提供商矩阵（当前行为）</h2><p><strong>OpenAI / OpenAI Codex</strong></p><ul><li>仅图片清理。</li><li>切换到 OpenAI Responses/Codex 模型时，丢弃孤立的推理签名（没有后续内容块的独立推理项）。</li><li>不进行工具调用 id 清理。</li><li>不进行工具结果配对修复。</li><li>不进行轮次验证或重新排序。</li><li>不生成合成工具结果。</li><li>不剥离思考签名。</li></ul><p><strong>Google (Generative AI / Gemini CLI / Antigravity)</strong></p><ul><li>工具调用 id 清理：严格字母数字。</li><li>工具结果配对修复和合成工具结果。</li><li>轮次验证（Gemini 风格的轮次交替）。</li><li>Google 轮次排序修正（如果历史记录以助手开头，则在前面添加一个小型用户引导消息）。</li><li>Antigravity Claude：规范化思考签名；丢弃未签名的思考块。</li></ul><p><strong>Anthropic / Minimax（Anthropic 兼容）</strong></p><ul><li>工具结果配对修复和合成工具结果。</li><li>轮次验证（合并连续的用户轮次以满足严格交替要求）。</li></ul><p><strong>Mistral（包括基于 model-id 的检测）</strong></p><ul><li>工具调用 id 清理：strict9（字母数字，长度 9）。</li></ul><p><strong>OpenRouter Gemini</strong></p><ul><li>思考签名清理：剥离非 base64 的 <code>thought_signature</code> 值（保留 base64）。</li></ul><p><strong>其他所有提供商</strong></p><ul><li>仅图片清理。</li></ul><hr><h2 id="历史行为-2026-1-22-之前" tabindex="-1"><a class="header-anchor" href="#历史行为-2026-1-22-之前">#</a> 历史行为（2026.1.22 之前）</h2><p>在 2026.1.22 版本发布之前，OpenSoul 应用了多层对话记录清理：</p><ul><li>一个<strong>对话记录清理扩展</strong>在每次上下文构建时运行，可以： <ul><li>修复工具使用/结果配对。</li><li>清理工具调用 id（包括保留 <code>_</code>/<code>-</code> 的非严格模式）。</li></ul></li><li>运行器也执行提供商特定的清理，导致重复工作。</li><li>在提供商策略之外还存在额外的变更，包括： <ul><li>在持久化之前从助手文本中剥离 <code>&lt;final&gt;</code> 标签。</li><li>丢弃空的助手错误轮次。</li><li>截断工具调用之后的助手内容。</li></ul></li></ul><p>这种复杂性导致了跨提供商的回归问题（尤其是 <code>openai-responses</code> 的 <code>call_id|fc_id</code> 配对）。2026.1.22 的清理移除了该扩展，将逻辑集中到运行器中，并使 OpenAI 在图片清理之外<strong>不做任何修改</strong>。</p>',35)])])}const u=i(n,[["render",s]]);export{h as __pageData,u as default};
